#include <bits/stdc++.h>
using namespace std;
double p(double x1,double y1,double x2,double y2)
{
    double j=sqrt(((x2-x1)*(x2-x1))+((y2-y1)*(y2-y1)));
    return j;
}
int main()
{
    double  a,b,c,d,e,f,t;
    cin>>a>>b>>c>>d>>e>>f;
    t=p(a,b,c,d)+p(a,b,e,f)+p(e,f,c,d);
    printf("%.2lf",t);
    return 0;
}
